document.addEventListener("DOMContentLoaded",function(){processItalicText()});function processItalicText(){const e=document.querySelectorAll("em, i");e.forEach(e=>{const s=e.textContent,t=/[\u4e00-\u9fa5]/.test(s),n=/[a-zA-Z]/.test(s);t&&!n?e.classList.add("chinese-italic"):n&&!t?e.classList.add("latin-italic"):t&&n&&processMixedContent(e)})}function processMixedContent(e){const t=e.textContent,n=t.split(/([\u4e00-\u9fa5]+|[a-zA-Z]+)/g);e.innerHTML="",n.forEach(t=>{if(!t)return;if(/[\u4e00-\u9fa5]/.test(t)){const n=document.createElement("span");n.className="chinese-italic",n.textContent=t,e.appendChild(n)}else if(/[a-zA-Z]/.test(t)){const n=document.createElement("span");n.className="latin-italic",n.textContent=t,e.appendChild(n)}else e.appendChild(document.createTextNode(t))})}